import{_ as a,c as e,o as l,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"스킬 관리: 사용 가능한 스킬 조회 | opencode-agent-skills","description":"get_available_skills 도구 사용법을 배워보세요. 검색, 네임스페이스 및 필터링을 통해 스킬을 빠르게 찾고, 스킬 발견 및 관리의 핵심 기능을 익히세요.","frontmatter":{"title":"스킬 관리: 사용 가능한 스킬 조회 | opencode-agent-skills","sidebarTitle":"스킬 빠르게 찾기","subtitle":"스킬 관리: 사용 가능한 스킬 조회","description":"get_available_skills 도구 사용법을 배워보세요. 검색, 네임스페이스 및 필터링을 통해 스킬을 빠르게 찾고, 스킬 발견 및 관리의 핵심 기능을 익히세요.","tags":["스킬 관리","도구 사용","네임스페이스"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"ko/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"ko/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}'),i={name:"ko/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function t(p,s,o,c,d,r){return l(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="사용-가능한-스킬-조회-및-목록화" tabindex="-1">사용 가능한 스킬 조회 및 목록화 <a class="header-anchor" href="#사용-가능한-스킬-조회-및-목록화" aria-label="Permalink to &quot;사용 가능한 스킬 조회 및 목록화&quot;">​</a></h1><h2 id="학습-완료-후-할-수-있는-것" tabindex="-1">학습 완료 후 할 수 있는 것 <a class="header-anchor" href="#학습-완료-후-할-수-있는-것" aria-label="Permalink to &quot;학습 완료 후 할 수 있는 것&quot;">​</a></h2><ul><li><code>get_available_skills</code> 도구를 사용하여 모든 사용 가능한 스킬 목록화</li><li>검색 쿼리를 통해 특정 스킬 필터링</li><li>네임스페이스(예: <code>project:skill-name</code>)를 사용하여 스킬 정확히 찾기</li><li>스킬 출처 및 실행 가능한 스크립트 목록 식별</li></ul><h2 id="현재의-어려움" tabindex="-1">현재의 어려움 <a class="header-anchor" href="#현재의-어려움" aria-label="Permalink to &quot;현재의 어려움&quot;">​</a></h2><p>특정 스킬을 사용하고 싶지만 정확한 이름이 기억나지 않습니다. 프로젝트 내의 어떤 스킬인지는 알지만 어떤 발견 경로에 있는지 모르거나, 현재 프로젝트에서 사용 가능한 스킬을 빠르게 둘러보고 싶을 수 있습니다.</p><h2 id="언제-이-기능을-사용하나요" tabindex="-1">언제 이 기능을 사용하나요 <a class="header-anchor" href="#언제-이-기능을-사용하나요" aria-label="Permalink to &quot;언제 이 기능을 사용하나요&quot;">​</a></h2><ul><li><strong>새 프로젝트 탐색</strong>: 새 프로젝트에 참여했을 때 사용 가능한 스킬 빠르게 파악</li><li><strong>스킬 이름 불확실</strong>: 스킬의 일부 이름이나 설명만 기억할 때, 퍼지 매칭 필요</li><li><strong>다중 네임스페이스 충돌</strong>: 프로젝트 수준과 사용자 수준에 동일한 이름의 스킬이 있을 때, 어떤 것을 사용할지 명확히 지정</li><li><strong>스크립트 찾기</strong>: 스킬 디렉토리에 어떤 실행 가능한 자동화 스크립트가 있는지 확인</li></ul><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><p><code>get_available_skills</code> 도구는 현재 세션에서 사용 가능한 모든 스킬을 확인하는 데 도움을 줍니다. 플러그인은 자동으로 6개의 발견 경로에서 스킬을 스캔합니다:</p><div class="info custom-block"><p class="custom-block-title">스킬 발견 우선순위</p><ol><li><code>.opencode/skills/</code> (프로젝트 수준 OpenCode)</li><li><code>.claude/skills/</code> (프로젝트 수준 Claude)</li><li><code>~/.config/opencode/skills/</code> (사용자 수준 OpenCode)</li><li><code>~/.claude/skills/</code> (사용자 수준 Claude)</li><li><code>~/.claude/plugins/cache/</code> (플러그인 캐시)</li><li><code>~/.claude/plugins/marketplaces/</code> (설치된 플러그인)</li></ol></div><p>동일한 이름의 스킬은 우선순위에 따라 첫 번째 것만 유지되고, 이후의 것은 무시됩니다.</p><p>도구가 반환하는 정보는 다음과 같습니다:</p><ul><li><strong>스킬 이름</strong></li><li><strong>출처 태그</strong> (project, user, claude-project 등)</li><li><strong>설명</strong></li><li><strong>실행 가능한 스크립트 목록</strong> (있는 경우)</li></ul><div class="tip custom-block"><p class="custom-block-title">네임스페이스 구문</p><p><code>namespace:skill-name</code> 형식으로 출처를 명확히 지정할 수 있습니다:</p><ul><li><code>project:my-skill</code> - 프로젝트 수준 OpenCode 스킬 사용 (<code>.opencode/skills/</code>)</li><li><code>claude-project:my-skill</code> - 프로젝트 수준 Claude 스킬 사용 (<code>.claude/skills/</code>)</li><li><code>user:my-skill</code> - 사용자 수준 OpenCode 스킬 사용 (<code>~/.config/opencode/skills/</code>)</li><li><code>claude-user:my-skill</code> - 사용자 수준 Claude 스킬 사용 (<code>~/.claude/skills/</code>)</li><li><code>claude-plugins:my-skill</code> - Claude 플러그인의 스킬 사용</li></ul></div><h2 id="따라-해보기" tabindex="-1">따라 해보기 <a class="header-anchor" href="#따라-해보기" aria-label="Permalink to &quot;따라 해보기&quot;">​</a></h2><h3 id="_1단계-모든-사용-가능한-스킬-목록화" tabindex="-1">1단계: 모든 사용 가능한 스킬 목록화 <a class="header-anchor" href="#_1단계-모든-사용-가능한-스킬-목록화" aria-label="Permalink to &quot;1단계: 모든 사용 가능한 스킬 목록화&quot;">​</a></h3><p>OpenCode에서 AI에게 직접 스킬 목록을 요청하세요:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자 입력:</span></span>
<span class="line"><span>사용 가능한 모든 스킬 목록화</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시스템 응답:</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Git 작업 및 브랜치 관리 도우미 [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  단위 테스트 및 커버리지 분석 도구</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 컨테이너화 및 배포 가이드 [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  완전한 소프트웨어 개발 워크플로우</span></span></code></pre></div><p><strong>보게 될 것</strong>: 스킬 목록으로, 각 스킬은 이름, 출처 태그, 설명, 스크립트 목록을 표시합니다.</p><h3 id="_2단계-검색-쿼리로-필터링" tabindex="-1">2단계: 검색 쿼리로 필터링 <a class="header-anchor" href="#_2단계-검색-쿼리로-필터링" aria-label="Permalink to &quot;2단계: 검색 쿼리로 필터링&quot;">​</a></h3><p>스킬의 일부 이름만 기억한다면:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자 입력:</span></span>
<span class="line"><span>&quot;docker&quot;가 포함된 스킬 찾기</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시스템 응답:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 컨테이너화 및 배포 가이드 [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>검색은 스킬 이름과 설명의 키워드를 매칭하며, <code>*</code> 와일드카드를 지원합니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자 입력:</span></span>
<span class="line"><span>&quot;test&quot;로 시작하는 스킬 찾기</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시스템 응답:</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  단위 테스트 및 커버리지 분석 도구</span></span></code></pre></div><p><strong>보게 될 것</strong>: 쿼리 조건과 일치하는 스킬만 표시됩니다.</p><h3 id="_3단계-퍼지-매칭-제안-체험" tabindex="-1">3단계: 퍼지 매칭 제안 체험 <a class="header-anchor" href="#_3단계-퍼지-매칭-제안-체험" aria-label="Permalink to &quot;3단계: 퍼지 매칭 제안 체험&quot;">​</a></h3><p>잘못된 스킬 이름을 입력하면:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자 입력:</span></span>
<span class="line"><span>docker-asistant를 사용하고 싶어요</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시스템 응답:</span></span>
<span class="line"><span>&quot;docker-asistant&quot;와 일치하는 스킬을 찾을 수 없습니다. &quot;docker-helper&quot;를 의미하셨나요?</span></span></code></pre></div><p>플러그인은 레벤슈타인 거리를 기반으로 유사도를 계산하여, 자동으로 가장 가까운 스킬 이름을 제안합니다.</p><p><strong>보게 될 것</strong>: 오류 메시지와 올바른 스킬 제안.</p><h3 id="_4단계-네임스페이스로-정확히-찾기" tabindex="-1">4단계: 네임스페이스로 정확히 찾기 <a class="header-anchor" href="#_4단계-네임스페이스로-정확히-찾기" aria-label="Permalink to &quot;4단계: 네임스페이스로 정확히 찾기&quot;">​</a></h3><p>프로젝트 수준과 사용자 수준에 모두 <code>build-helper</code>라는 이름의 스킬이 있다고 가정해 봅시다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자 입력:</span></span>
<span class="line"><span>build-helper의 상세 정보 목록화</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시스템 응답:</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  프로젝트별 빌드 구성 및 컴파일 최적화 [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>사용자가 사용자 수준의 스킬을 원한다면:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자 입력:</span></span>
<span class="line"><span>user:build-helper 사용</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시스템 응답:</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  일반 빌드 도구체인 및 지속적 통합 구성 [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>보게 될 것</strong>: 네임스페이스 접두사를 통해 다른 출처의 동일한 이름 스킬에 접근할 수 있습니다.</p><h3 id="_5단계-실행-가능한-스크립트-확인" tabindex="-1">5단계: 실행 가능한 스크립트 확인 <a class="header-anchor" href="#_5단계-실행-가능한-스크립트-확인" aria-label="Permalink to &quot;5단계: 실행 가능한 스크립트 확인&quot;">​</a></h3><p>스킬 디렉토리에 어떤 스크립트가 있는지 확인:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자 입력:</span></span>
<span class="line"><span>docker-helper에 어떤 스크립트가 있나요?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시스템 응답:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 컨테이너화 및 배포 가이드 [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>스크립트는 스킬 정보의 대괄호 안에 쉼표로 구분되어 표시됩니다. <code>run_skill_script</code> 도구로 이러한 스크립트를 실행할 수 있습니다.</p><p><strong>보게 될 것</strong>: 스킬 이름 뒤에 <code>[scripts: 스크립트경로1, 스크립트경로2, ...]</code> 형식의 목록이 표시됩니다.</p><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><ul><li>[ ] 사용 가능한 모든 스킬을 목록화할 수 있나요?</li><li>[ ] 검색 쿼리로 특정 스킬을 필터링할 수 있나요?</li><li>[ ] 스킬 출처 태그의 의미를 이해하나요 (project, user, claude-project 등)?</li><li>[ ] 스킬 네임스페이스의 역할과 구문을 설명할 수 있나요?</li><li>[ ] 스킬 정보에서 실행 가능한 스크립트 목록을 식별할 수 있나요?</li></ul><h2 id="주의사항" tabindex="-1">주의사항 <a class="header-anchor" href="#주의사항" aria-label="Permalink to &quot;주의사항&quot;">​</a></h2><h3 id="함정-1-동일-이름-스킬의-덮어쓰기" tabindex="-1">함정 1: 동일 이름 스킬의 덮어쓰기 <a class="header-anchor" href="#함정-1-동일-이름-스킬의-덮어쓰기" aria-label="Permalink to &quot;함정 1: 동일 이름 스킬의 덮어쓰기&quot;">​</a></h3><p>프로젝트 수준과 사용자 수준에 동일한 이름의 스킬이 있으면, 예상한 스킬이 로드되지 않는 것에 대해 혼란스러울 수 있습니다.</p><p><strong>원인</strong>: 스킬은 우선순위에 따라 발견되며, 프로젝트 수준이 사용자 수준보다 우선하고, 동일한 이름은 첫 번째 것만 유지됩니다.</p><p><strong>해결</strong>: 네임스페이스를 사용하여 명확히 지정하세요. 예: <code>user:my-skill</code> 대신 <code>my-skill</code>.</p><h3 id="함정-2-검색-대소문자-구분" tabindex="-1">함정 2: 검색 대소문자 구분 <a class="header-anchor" href="#함정-2-검색-대소문자-구분" aria-label="Permalink to &quot;함정 2: 검색 대소문자 구분&quot;">​</a></h3><p>검색 쿼리는 정규 표현식을 사용하지만 <code>i</code> 플래그가 설정되어 있어 대소문자를 구분하지 않습니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 이 검색들은 동일합니다</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="함정-3-와일드카드-이스케이프" tabindex="-1">함정 3: 와일드카드 이스케이프 <a class="header-anchor" href="#함정-3-와일드카드-이스케이프" aria-label="Permalink to &quot;함정 3: 와일드카드 이스케이프&quot;">​</a></h3><p>검색에서 <code>*</code>는 자동으로 <code>.*</code> 정규 표현식으로 변환되며, 수동으로 이스케이프할 필요가 없습니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># &quot;test&quot;로 시작하는 스킬 검색</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 정규 표현식 /test.*/i와 동일</span></span></code></pre></div><h2 id="강의-요약" tabindex="-1">강의 요약 <a class="header-anchor" href="#강의-요약" aria-label="Permalink to &quot;강의 요약&quot;">​</a></h2><p><code>get_available_skills</code>는 스킬 생태계를 탐색하는 도구로, 다음을 지원합니다:</p><ul><li><strong>모든 스킬 목록화</strong>: 매개변수 없이 호출</li><li><strong>검색 필터링</strong>: <code>query</code> 매개변수로 이름과 설명 매칭</li><li><strong>네임스페이스</strong>: <code>namespace:skill-name</code>으로 정확히 찾기</li><li><strong>퍼지 매칭 제안</strong>: 철자 오류 시 자동으로 올바른 이름 제안</li><li><strong>스크립트 목록</strong>: 실행 가능한 자동화 스크립트 표시</li></ul><p>플러그인은 세션 시작 시 자동으로 스킬 목록을 주입하므로, 일반적으로 이 도구를 수동으로 호출할 필요가 없습니다. 하지만 다음 시나리오에서 유용합니다:</p><ul><li>사용 가능한 스킬을 빠르게 둘러보고 싶을 때</li><li>스킬의 정확한 이름이 기억나지 않을 때</li><li>동일한 이름의 스킬의 다른 출처를 구분해야 할 때</li><li>특정 스킬의 스크립트 목록을 확인하고 싶을 때</li></ul><h2 id="다음-강의-예고" tabindex="-1">다음 강의 예고 <a class="header-anchor" href="#다음-강의-예고" aria-label="Permalink to &quot;다음 강의 예고&quot;">​</a></h2><blockquote><p>다음 강의에서는 **<a href="./../loading-skills-into-context/">세션 컨텍스트에 스킬 로드</a>**를 배웁니다.</p><p>배울 내용:</p><ul><li>use_skill 도구를 사용하여 현재 세션에 스킬 로드</li><li>스킬 콘텐츠가 XML 형식으로 컨텍스트에 주입되는 방식 이해</li><li>Synthetic Message Injection 메커니즘(합성 메시지 주입) 익히기</li><li>세션 압축 후 스킬이 어떻게 계속 사용 가능한지 알아보기</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>라인 번호</th></tr></thead><tbody><tr><td>GetAvailableSkills 도구 정의</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>discoverAllSkills 함수</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>resolveSkill 함수</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>findClosestMatch 함수</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>주요 타입</strong>:</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code>: 스킬 출처 태그 열거형</li></ul><p><strong>주요 상수</strong>:</p><ul><li>퍼지 매칭 임계값: <code>0.4</code> (<code>utils.ts:124</code>) - 유사도가 이 값보다 낮으면 제안을 반환하지 않음</li></ul><p><strong>주요 함수</strong>:</p><ul><li><code>GetAvailableSkills()</code>: 쿼리 필터링 및 퍼지 매칭 제안을 지원하는 형식화된 스킬 목록 반환</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code>: <code>namespace:skill-name</code> 형식의 스킬 파싱 지원</li><li><code>findClosestMatch(input: string, candidates: string[])</code>: 다양한 매칭 전략(접두사, 포함, 편집 거리)을 기반으로 최적 매칭 계산</li></ul><p><strong>비즈니스 규칙</strong>:</p><ul><li>동일한 이름의 스킬은 발견 순서에 따라 중복 제거되며, 첫 번째 것만 유지됨 (<code>skills.ts:258</code>)</li><li>검색 쿼리는 와일드카드 <code>*</code>를 지원하며, 자동으로 정규 표현식으로 변환됨 (<code>tools.ts:43</code>)</li><li>퍼지 매칭 제안은 쿼리 매개변수가 있고 결과가 없을 때만 트리거됨 (<code>tools.ts:49-57</code>)</li></ul></details>`,64)])])}const k=a(i,[["render",t]]);export{u as __pageData,k as default};
